// ========================================
// CRITICAL: Infinite Loop Prevention Filter
// ROOT CAUSE of 143% CPU issue
// ========================================

// Get the payload
const payload = $input.item.json.payload || $input.item.json.body || $input.item.json;

// Filter 1: Ignore broadcast messages (status@broadcast)
// This is the MAIN cause of infinite loop
if (payload.from === 'status@broadcast') {
  return [];
}

// Filter 2: Ignore empty messages
if (!payload.body && !payload.text) {
  return [];
}

const messageText = (payload.body || payload.text || '').trim();
if (messageText === '') {
  return [];
}

// Filter 3: Ignore own messages (fromMe = true)
if (payload.fromMe === true) {
  return [];
}

// Filter 4: Ignore messages with only media (no text)
if (payload.hasMedia && !payload.body && !payload.text) {
  return [];
}

// Filter 5: Ignore system messages
if (payload.type && ['e2e_notification', 'notification_template'].includes(payload.type)) {
  return [];
}

// If all filters pass, continue workflow
return {
  json: {
    ...$input.item.json,
    _filtered: false,
    _timestamp: new Date().toISOString()
  }
};

