// Extract message data from WAHA webhook
const body = $input.item.json.body || $input.item.json;

return {
  phone: body.from || '',
  message: body.body || body.text || '',
  sender_name: body.notifyName || body.from || 'Warga',
  timestamp: body.timestamp || Date.now(),
  source: 'whatsapp',
  raw_data: body
};

// Validate and normalize payload
const phone = $input.item.json.phone || '';
const message = $input.item.json.message || '';
const type = $input.item.json.type || 'manual_reply';

if (!phone || !message) {
  throw new Error('Phone and message are required');
}

// Normalize phone number
let normalizedPhone = phone.replace(/[^0-9]/g, '');
if (normalizedPhone.startsWith('0')) {
  normalizedPhone = '62' + normalizedPhone.substring(1);
}

return {
  phone: normalizedPhone,
  message: message,
  type: type,
  source: 'dashboard',
  timestamp: new Date().toISOString()
};

// Check for commands
const message = ($json.message || '').toLowerCase().trim();

if (message.startsWith('/status')) {
  const parts = $json.message.split(' ');
  return { ...$json, command: 'status', uuid: parts[1] || null };
} else if (message.startsWith('/help')) {
  return { ...$json, command: 'help' };
} else if (message.startsWith('/faq')) {
  return { ...$json, command: 'faq', keyword: $json.message.replace('/faq', '').trim() };
} else if (message.startsWith('/')) {
  return { ...$json, command: 'unknown' };
}

return { ...$json, command: 'normal' };

// Build status message
const data = $json.data || $json;

if (!data.found) {
  return {
    phone: $('Extract WhatsApp').item.json.phone,
    message: 'âťŚ *Laporan tidak ditemukan*\n\nPastikan ID atau nomor WhatsApp yang Anda masukkan sudah benar.\n\nđź’ˇ Gunakan format: `/status {uuid}` atau ketik `/help` untuk bantuan',
    type: 'status_reply'
  };
}

let msg = 'đź“Š *Status Laporan*\n\n';
