msg += `đź“Š Status: *${data.status_label}*\n`;
msg += `đź“… Dibuat: ${data.created_at}\n\n`;

if (data.public_response) {
  msg += `đź“ť *Respon:*\n${data.public_response}\n\n`;
}

msg += 'đź’ˇ Ketik `/status ' + data.uuid + '` untuk cek status kapan saja.';

return {
